import bcrypt2 from "bcryptjs";
import jwt2 from "jsonwebtoken";
import httpStatus2 from "http-status";
var loginUserFromDB = async (email, password) => {
  const user = await prisma.user.findUnique({
    where: {
      email
    }
  });
  if (!user) {
    throw new AppError_default(httpStatus2.UNAUTHORIZED, "Invalid email or password");
  }
  if (user.activeStatus === "BANNED") {
    throw new AppError_default(httpStatus2.FORBIDDEN, "Your account has been banned");
  }
  const isPasswordMatched = await bcrypt2.compare(password, user.password);
  if (!isPasswordMatched) {
    throw new AppError_default(httpStatus2.UNAUTHORIZED, "Invalid email or password");
  }
  const accessToken = jwt2.sign(
    {
      id: user.id,
      email: user.email,
      name: user.name,
      role: user.role
    },
    config_default.jwt_access_secret,
    {
      expiresIn: config_default.jwt_access_expires_in
    }
  );
  const { password: _, ...userWithoutPassword } = user;
  return {
    accessToken,
    user: userWithoutPassword
  };
};
var registerUserIntoDB2 = async (data) => {
  const exists = await prisma.user.findUnique({
    where: {
      email: data.email
    }
  });
  if (exists) {
    throw new AppError_default(httpStatus2.CONFLICT, "Email already exists");
  }
  const hashedPassword = await bcrypt2.hash(data.password, 12);
  const user = await prisma.user.create({
    data: {
      name: data.name,
      email: data.email,
      password: hashedPassword,
      role: data.role
    }
  });
  const { password: _, ...safeUser } = user;
  return safeUser;
};
var getMeFromDB = async (userId) => {
  const user = await prisma.user.findUnique({
    where: {
      id: userId
    },
    omit: {
      password: true
    },
    include: {
      profile: true
    }
  });
  if (!user) {
    throw new AppError_default(httpStatus2.NOT_FOUND, "User not found");
  }
  return user;
};
