import { Router as Router5 } from "express";

// src/modules/rentalRequest/rentalRequest.controller.ts
import httpStatus6 from "http-status";

// src/modules/rentalRequest/rentalRequest.service.ts
var createRentalRequestIntoDB = async (tenantId, payload) => {
  const property = await prisma.property.findUnique({
    where: {
      id: payload.propertyId
    }
  });
  if (!property) {
    throw new AppError_default(404, "Property not found");
  }
  if (property.availability !== "AVAILABLE") {
    throw new AppError_default(400, "Property is not available");
  }
  const existingRequest = await prisma.rentalRequest.findFirst({
    where: {
      tenantId,
      propertyId: payload.propertyId,
      status: {
        in: [RentalStatus.PENDING, RentalStatus.APPROVED]
      }
    }
  });
  if (existingRequest) {
    throw new AppError_default(
      400,
      "You already have an active request for this property"
    );
  }
  const rentalRequest = await prisma.rentalRequest.create({
    data: {
      tenantId,
      propertyId: payload.propertyId,
      moveInDate: new Date(payload.moveInDate),
      duration: payload.duration,
      message: payload.message
    },
    include: {
      property: {
        include: {
          category: true
        }
      }
    }
  });
  return rentalRequest;
};
var getMyRentalRequestsFromDB = async (tenantId) => {
  return prisma.rentalRequest.findMany({
    where: {
      tenantId
    },
    include: {
      property: {
        include: {
          category: true
        }
      }
    },
    orderBy: {
      createdAt: "desc"
    }
  });
};
var getSingleRentalRequestFromDB = async (tenantId, id) => {
  return prisma.rentalRequest.findFirstOrThrow({
    where: {
      id,
      tenantId
    },
    include: {
      property: {
        include: {
          category: true
        }
      }
    }
  });
};
var getLandlordRequestsFromDB = async (landlordId) => {
  return prisma.rentalRequest.findMany({
    where: {
      property: {
        landlordId
      }
    },
    include: {
      tenant: {
        omit: {
          password: true
        }
      },
      property: true
    },
    orderBy: {
      createdAt: "desc"
    }
  });
};
var updateRentalRequestStatusIntoDB = async (landlordId, rentalRequestId, payload) => {
  const rentalRequest = await prisma.rentalRequest.findFirst({
    where: {
      id: rentalRequestId,
      property: {
        landlordId
      }
    }
  });
  if (!rentalRequest) {
    throw new AppError_default(404, "Rental request not found");
  }
  if (rentalRequest.status === RentalStatus.REJECTED || rentalRequest.status === RentalStatus.COMPLETED) {
    throw new AppError_default(400, "Rental request cannot be updated");
  }
  const updatedRequest = await prisma.rentalRequest.update({
    where: {
      id: rentalRequestId
    },
    data: {
      status: payload.status
    },
    include: {
      tenant: {
        omit: {
          password: true
        }
      },
      property: true
    }
  });
  if (payload.status === RentalStatus.APPROVED) {
    await prisma.property.update({
      where: {
        id: updatedRequest.propertyId
      },
      data: {
        availability: "RENTED"
      }
    });
  }
  if (payload.status === RentalStatus.COMPLETED) {
    await prisma.property.update({
      where: {
        id: updatedRequest.propertyId
      },
      data: {
        availability: "AVAILABLE"
      }
    });
  }
  return updatedRequest;
};
var rentalRequestService = {
  createRentalRequestIntoDB,
  getMyRentalRequestsFromDB,
  getSingleRentalRequestFromDB,
  getLandlordRequestsFromDB,
  updateRentalRequestStatusIntoDB
};

